export declare const P45_HTML =
  '<!DOCTYPE html>\n<html lang="en">\n<head>\n  <meta charset="UTF-8" />\n  <title>P45 {{document.number}}</title>\n  <style>\n    /* P45-specific overrides \u2014 HMRC-style formal layout */\n    .p45-subtitle {\n      font-size: 12px;\n      color: #555;\n      margin-bottom: 16px;\n    }\n    .p45-section {\n      margin-bottom: 16px;\n      padding: 12px;\n      border: 1px solid #ccc;\n      border-radius: 4px;\n      page-break-inside: avoid;\n    }\n    .p45-section .section-title {\n      font-size: 10px;\n      font-weight: 700;\n      text-transform: uppercase;\n      color: #888;\n      margin-bottom: 8px;\n      padding-bottom: 4px;\n      border-bottom: 1px solid #e5e5e5;\n    }\n    .p45-section table {\n      width: 100%;\n      border-collapse: collapse;\n    }\n    .p45-section td {\n      padding: 4px 12px 4px 0;\n      font-size: 11px;\n      vertical-align: top;\n    }\n    .p45-section td:nth-child(odd) {\n      font-weight: 600;\n      color: #555;\n      width: 180px;\n    }\n    .p45-figures {\n      margin-bottom: 16px;\n      page-break-inside: avoid;\n    }\n    .p45-figures table {\n      width: 100%;\n      max-width: 500px;\n      border-collapse: collapse;\n    }\n    .p45-figures thead th {\n      background: #f0f0f0;\n      font-size: 10px;\n      font-weight: 700;\n      text-transform: uppercase;\n      color: #555;\n      padding: 8px 6px;\n      border-bottom: 2px solid #ccc;\n      text-align: left;\n    }\n    .p45-figures thead th.text-right {\n      text-align: right;\n    }\n    .p45-figures tbody td {\n      padding: 6px;\n      border-bottom: 1px solid #e5e5e5;\n      font-size: 11px;\n    }\n    .p45-figures tbody td.text-right {\n      text-align: right;\n      font-variant-numeric: tabular-nums;\n    }\n    .p45-figures tbody td.figure {\n      font-weight: 700;\n      font-size: 13px;\n    }\n    .p45-important {\n      margin: 16px 0;\n      padding: 10px 14px;\n      border: 2px solid #b91c1c;\n      background: #fef2f2;\n      color: #991b1b;\n      font-size: 11px;\n      font-weight: 600;\n      text-align: center;\n      border-radius: 4px;\n    }\n    .p45-part-label {\n      display: inline-block;\n      background: #333;\n      color: #fff;\n      font-size: 10px;\n      font-weight: 700;\n      padding: 2px 8px;\n      border-radius: 2px;\n      margin-bottom: 8px;\n    }\n  </style>\n</head>\n<body>\n  <div class="page">\n\n    \n<div class="header">\n  <div class="header-left">\n    {{#if branding.showLogo}}\n    {{#if company.logoUrl}}\n    <div class="logo-section">\n      <img src="{{company.logoUrl}}" alt="{{company.name}} logo" />\n    </div>\n    {{/if}}\n    {{/if}}\n    <div class="company-name">{{company.name}}</div>\n    {{#if company.legalName}}\n    <div class="company-legal-name">{{company.legalName}}</div>\n    {{/if}}\n  </div>\n  <div class="header-right">\n    <div class="company-details">\n      <p style="white-space:pre-line">{{company.address}}</p>\n      {{#if company.phone}}<p>Tel: {{company.phone}}</p>{{/if}}\n      {{#if company.email}}<p>{{company.email}}</p>{{/if}}\n      {{#if company.website}}<p>{{company.website}}</p>{{/if}}\n      {{#if branding.showVatNumber}}\n      {{#if company.vatNumber}}<p class="vat-number">VAT: {{company.vatNumber}}</p>{{/if}}\n      {{/if}}\n      {{#if branding.showCompanyReg}}\n      {{#if company.companyNumber}}<p class="company-reg">Reg: {{company.companyNumber}}</p>{{/if}}\n      {{/if}}\n    </div>\n  </div>\n</div>\n\n    <div class="document-title">P45</div>\n    <div class="p45-subtitle">Details of employee leaving work</div>\n\n    <div class="p45-part-label">Part 1A \u2014 Employee\'s Copy</div>\n\n    <div class="p45-section">\n      <div class="section-title">Employee Details</div>\n      <table>\n        <tr>\n          <td>Full Name</td>\n          <td>{{counterparty.name}}</td>\n        </tr>\n        <tr>\n          <td>Address</td>\n          <td>{{counterparty.address}}</td>\n        </tr>\n        {{#if document.notes}}\n        <tr>\n          <td>NI Number / Tax Code</td>\n          <td>{{document.notes}}</td>\n        </tr>\n        {{/if}}\n      </table>\n    </div>\n\n    <div class="p45-section">\n      <div class="section-title">Leaving Details</div>\n      <table>\n        <tr>\n          <td>P45 Reference</td>\n          <td>{{document.number}}</td>\n        </tr>\n        <tr>\n          <td>Leaving Date</td>\n          <td>{{formatDate document.date}}</td>\n        </tr>\n        {{#if document.reference}}\n        <tr>\n          <td>Details</td>\n          <td>{{document.reference}}</td>\n        </tr>\n        {{/if}}\n      </table>\n    </div>\n\n    <div class="p45-section">\n      <div class="section-title">Employer Details</div>\n      <table>\n        <tr>\n          <td>Employer Name</td>\n          <td>{{company.name}}</td>\n        </tr>\n        {{#if company.companyNumber}}\n        <tr>\n          <td>Employer PAYE Reference</td>\n          <td>{{company.companyNumber}}</td>\n        </tr>\n        {{/if}}\n        <tr>\n          <td>Employer Address</td>\n          <td>{{company.address}}</td>\n        </tr>\n      </table>\n    </div>\n\n    <div class="p45-figures">\n      <table>\n        <thead>\n          <tr>\n            <th>Description</th>\n            <th class="text-right">Amount</th>\n          </tr>\n        </thead>\n        <tbody>\n          {{#each lines}}\n          <tr class="line-item-row">\n            <td>{{this.description}}</td>\n            <td class="text-right figure">{{formatCurrency this.lineTotal ../metadata.currencyCode}}</td>\n          </tr>\n          {{/each}}\n        </tbody>\n      </table>\n    </div>\n\n    <div class="p45-important">\n      IMPORTANT \u2014 Please give Parts 2 and 3 to your new employer.<br/>\n      If you do not have a new employer, keep this form safe. You may need it to claim benefits or for your tax return.\n    </div>\n\n    <div class="notice notice-info">\n      This document is an approximation of the HMRC P45 format produced by the payroll system for information purposes.\n    </div>\n\n    \n<div class="page-footer">\n  {{company.name}} &mdash; Generated by Nexa ERP\n  <div class="page-numbers">Page <span class="pageNumber"></span> of <span class="totalPages"></span></div>\n</div>\n\n  </div>\n</body>\n</html>';
